<template>
  <div class="bg-gray-50 dark:bg-gray-900 min-h-screen py-8">
    <div class="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
      <div class="md:flex md:items-center md:justify-between mb-8">
        <div class="flex-1 min-w-0">
          <h2 class="text-2xl font-bold leading-7 text-gray-900 dark:text-white sm:text-3xl sm:truncate">
            Studies
          </h2>
          <p class="mt-1 text-sm text-gray-500 dark:text-gray-400">
            Access and manage study documents from the shared Drive folder.
          </p>
        </div>
        <div class="mt-4 flex md:mt-0 md:ml-4">
          <a
            :href="driveFolderUrl"
            target="_blank"
            class="ml-3 inline-flex items-center px-4 py-2 border border-transparent rounded-md shadow-sm text-sm font-medium text-white bg-indigo-600 hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500 transition-colors duration-200"
          >
            <svg class="-ml-1 mr-2 h-5 w-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
               <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" />
            </svg>
            Open in Drive
          </a>
        </div>
      </div>

      <!-- Auth State -->
      <div v-if="!isAuthenticated && !loading && files.length === 0" class="text-center py-12 bg-white dark:bg-gray-800 shadow rounded-lg">
         <svg class="mx-auto h-12 w-12 text-gray-400" fill="none" viewBox="0 0 24 24" stroke="currentColor" aria-hidden="true">
            <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" />
         </svg>
         <h3 class="mt-2 text-sm font-medium text-gray-900 dark:text-white">Authentication Required</h3>
         <p class="mt-1 text-sm text-gray-500 dark:text-gray-400">Please sign in with Google to view the documents.</p>
         <div class="mt-6">
            <button @click="authorize" class="inline-flex items-center px-4 py-2 border border-transparent shadow-sm text-sm font-medium rounded-md text-white bg-indigo-600 hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500">
               Sign In with Google
            </button>
         </div>
      </div>

      <!-- Loading State -->
      <div v-else-if="loading" class="flex flex-col items-center justify-center py-20">
         <svg class="animate-spin -ml-1 mr-3 h-8 w-8 text-indigo-500" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle class="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" stroke-width="4"></circle>
            <path class="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
         </svg>
         <p class="mt-4 text-sm text-gray-500 dark:text-gray-400">Loading documents...</p>
      </div>

      <!-- Error State -->
      <div v-else-if="error" class="bg-red-50 dark:bg-red-900 p-4 rounded-md mb-8">
        <div class="flex">
          <div class="flex-shrink-0">
            <svg class="h-5 w-5 text-red-400" viewBox="0 0 20 20" fill="currentColor" aria-hidden="true">
              <path fill-rule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clip-rule="evenodd" />
            </svg>
          </div>
          <div class="ml-3">
            <h3 class="text-sm font-medium text-red-800 dark:text-red-200">Error loading documents</h3>
            <div class="mt-2 text-sm text-red-700 dark:text-red-300">
              <p>{{ error }}</p>
            </div>
            <div class="mt-4">
                 <button @click="loadDocuments" class="text-sm font-medium text-red-800 dark:text-red-200 hover:text-red-900 underline">Try Again</button>
            </div>
          </div>
        </div>
      </div>

      <!-- Data Table -->
      <div v-else class="flex flex-col">
        <div class="-my-2 overflow-x-auto sm:-mx-6 lg:-mx-8">
          <div class="py-2 align-middle inline-block min-w-full sm:px-6 lg:px-8">
            <div class="shadow overflow-hidden border-b border-gray-200 dark:border-gray-700 sm:rounded-lg">
              <table class="min-w-full divide-y divide-gray-200 dark:divide-gray-700">
                <thead class="bg-gray-50 dark:bg-gray-800">
                  <tr>
                    <th
                      scope="col"
                      class="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-300 uppercase tracking-wider cursor-pointer hover:bg-gray-100 dark:hover:bg-gray-700 transition w-1/2"
                      @click="sortBy('name')"
                    >
                      <div class="flex items-center space-x-1">
                          <span>Title</span>
                          <span v-if="sortKey === 'name'" class="text-indigo-500">
                              <svg v-if="sortOrder === 'asc'" class="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M5 15l7-7 7 7" /></svg>
                              <svg v-else class="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M19 9l-7 7-7-7" /></svg>
                          </span>
                      </div>
                    </th>
                    <th
                      scope="col"
                      class="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-300 uppercase tracking-wider cursor-pointer hover:bg-gray-100 dark:hover:bg-gray-700 transition"
                      @click="sortBy('owners')"
                    >
                      <div class="flex items-center space-x-1">
                          <span>Author</span>
                           <span v-if="sortKey === 'owners'" class="text-indigo-500">
                              <svg v-if="sortOrder === 'asc'" class="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M5 15l7-7 7 7" /></svg>
                              <svg v-else class="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M19 9l-7 7-7-7" /></svg>
                          </span>
                      </div>
                    </th>
                    <th
                      scope="col"
                      class="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-300 uppercase tracking-wider cursor-pointer hover:bg-gray-100 dark:hover:bg-gray-700 transition"
                      @click="sortBy('modifiedTime')"
                    >
                      <div class="flex items-center space-x-1">
                          <span>Last Modified</span>
                          <span v-if="sortKey === 'modifiedTime'" class="text-indigo-500">
                              <svg v-if="sortOrder === 'asc'" class="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M5 15l7-7 7 7" /></svg>
                              <svg v-else class="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M19 9l-7 7-7-7" /></svg>
                          </span>
                      </div>
                    </th>
                    <th scope="col" class="relative px-6 py-3">
                      <span class="sr-only">Open</span>
                    </th>
                  </tr>
                </thead>
                <tbody class="bg-white dark:bg-gray-800 divide-y divide-gray-200 dark:divide-gray-700">
                  <tr v-for="file in sortedFiles" :key="file.id" class="hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors duration-150">
                    <td class="px-6 py-4 whitespace-nowrap">
                      <div class="flex items-center">
                        <div class="flex-shrink-0 h-8 w-8">
                          <img class="h-8 w-8 rounded-sm" :src="file.iconLink" alt="" v-if="file.iconLink">
                          <div v-else class="h-8 w-8 bg-gray-200 rounded-full flex items-center justify-center text-xs text-gray-500">?</div>
                        </div>
                        <div class="ml-4">
                          <div class="text-sm font-medium text-gray-900 dark:text-white">
                             <a :href="file.webViewLink" target="_blank" class="hover:underline text-indigo-600 dark:text-indigo-400">{{ file.name }}</a>
                          </div>
                        </div>
                      </div>
                    </td>
                    <td class="px-6 py-4 whitespace-nowrap">
                      <div class="text-sm text-gray-500 dark:text-gray-300">
                          <div v-if="file.owners && file.owners.length" class="flex items-center space-x-2">
                             <img :src="file.owners[0].photoLink" class="w-6 h-6 rounded-full" v-if="file.owners[0].photoLink">
                             <span>{{ file.owners[0].displayName }}</span>
                          </div>
                          <span v-else>Unknown</span>
                      </div>
                    </td>
                    <td class="px-6 py-4 whitespace-nowrap">
                      <div class="text-sm text-gray-500 dark:text-gray-400">{{ new Date(file.modifiedTime).toLocaleString() }}</div>
                    </td>
                    <td class="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                      <a :href="file.webViewLink" target="_blank" class="text-indigo-600 dark:text-indigo-400 hover:text-indigo-900 dark:hover:text-indigo-300">Open</a>
                    </td>
                  </tr>
                </tbody>
              </table>
            </div>
            <!-- Empty state in table -->
             <div v-if="sortedFiles.length === 0" class="text-center py-8">
                 <p class="text-gray-500 dark:text-gray-400">No documents found in this folder.</p>
             </div>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import { listFiles } from '../services/drive';
import { auth } from '../firebase';
import { GoogleAuthProvider, signInWithPopup } from 'firebase/auth';

export default {
  name: 'Studies',
  data() {
    return {
      folderId: '1OxQ5Y8phz48ydqTqZ72sDKCU0IdF4SU6',
      files: [],
      loading: false,
      error: null,
      sortKey: 'modifiedTime',
      sortOrder: 'desc', // 'asc' or 'desc'
      isAuthenticated: false
    }
  },
  computed: {
    driveFolderUrl() {
        return `https://drive.google.com/drive/folders/${this.folderId}`;
    },
    sortedFiles() {
        return [...this.files].sort((a, b) => {
            let modifier = this.sortOrder === 'asc' ? 1 : -1;

            if (this.sortKey === 'name') {
                return a.name.localeCompare(b.name) * modifier;
            } else if (this.sortKey === 'owners') {
                const ownerA = a.owners && a.owners[0] ? a.owners[0].displayName : '';
                const ownerB = b.owners && b.owners[0] ? b.owners[0].displayName : '';
                return ownerA.localeCompare(ownerB) * modifier;
            } else if (this.sortKey === 'modifiedTime') {
                return (new Date(a.modifiedTime) - new Date(b.modifiedTime)) * modifier;
            }
            return 0;
        });
    }
  },
  mounted() {
      this.checkAuthAndLoad();
  },
  methods: {
    async checkAuthAndLoad() {
        const token = localStorage.getItem('drive_access_token');
        if (token) {
            this.isAuthenticated = true;
            this.loadDocuments();
        } else {
             // Try to check if firebase auth is ready, but for drive scope we specifically need the token.
             // We can just flip isAuthenticated to false and show login.
             this.isAuthenticated = false;
        }
    },
    async authorize() {
        const provider = new GoogleAuthProvider();
        provider.addScope('https://www.googleapis.com/auth/drive.readonly');

        try {
            this.loading = true;
            const result = await signInWithPopup(auth, provider);
            const credential = GoogleAuthProvider.credentialFromResult(result);
            const token = credential.accessToken;
            localStorage.setItem('drive_access_token', token);
            this.isAuthenticated = true;
            await this.loadDocuments();
        } catch (error) {
            console.error("Auth error:", error);
            this.error = "Authentication failed: " + error.message;
        } finally {
            this.loading = false;
        }
    },
    async loadDocuments() {
        this.loading = true;
        this.error = null;
        try {
            const token = localStorage.getItem('drive_access_token');
            if (!token) throw new Error("No access token found");

            this.files = await listFiles(this.folderId, token);
        } catch (e) {
            console.error("Load error:", e);
            if (e.message.includes('401') || e.message.includes('Unauthorized')) {
                this.isAuthenticated = false;
                this.error = "Session expired. Please sign in again.";
                localStorage.removeItem('drive_access_token');
            } else {
                this.error = e.message;
            }
        } finally {
            this.loading = false;
        }
    },
    sortBy(key) {
        if (this.sortKey === key) {
            this.sortOrder = this.sortOrder === 'asc' ? 'desc' : 'asc';
        } else {
            this.sortKey = key;
            this.sortOrder = 'asc';
        }
    }
  }
}
</script>
