<template>
  <div id="app" class="min-h-screen bg-gray-100 dark:bg-gray-900 text-gray-900 dark:text-gray-100 font-sans transition-colors duration-200">
    <header class="bg-white dark:bg-gray-800 shadow transition-colors duration-200">
      <div class="max-w-7xl mx-auto py-6 px-4 sm:px-6 lg:px-8 flex flex-col sm:flex-row justify-between items-center">
        <h1 class="text-3xl font-bold text-gray-900 dark:text-white mb-4 sm:mb-0">
          Freedeliar
        </h1>
        <div v-if="user" class="flex items-center space-x-4">
           <router-link to="/" exact active-class="text-gray-900 dark:text-white font-bold" class="text-sm text-gray-600 dark:text-gray-300 hover:text-gray-900 dark:hover:text-white">Generate</router-link>
           <router-link to="/history" active-class="text-gray-900 dark:text-white font-bold" class="text-sm text-gray-600 dark:text-gray-300 hover:text-gray-900 dark:hover:text-white">History</router-link>
           <router-link to="/templates" active-class="text-gray-900 dark:text-white font-bold" class="text-sm text-gray-600 dark:text-gray-300 hover:text-gray-900 dark:hover:text-white">Templates</router-link>
           <router-link to="/studies" active-class="text-gray-900 dark:text-white font-bold" class="text-sm text-gray-600 dark:text-gray-300 hover:text-gray-900 dark:hover:text-white">Studies</router-link>
           <router-link to="/settings" active-class="text-gray-900 dark:text-white font-bold" class="text-sm text-gray-600 dark:text-gray-300 hover:text-gray-900 dark:hover:text-white">Settings</router-link>
           <ThemeToggle />
           <button @click="logout" class="text-sm text-red-600 dark:text-red-400 hover:text-red-800 dark:hover:text-red-300">Logout</button>
        </div>
      </div>
    </header>
    <main>
      <div class="max-w-7xl mx-auto py-6 sm:px-6 lg:px-8">
        <div v-if="loading" class="flex justify-center items-center h-64">
          <div class="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
        </div>
        <template v-else>
          <Login v-if="!user" @login-success="handleLogin" />
          <router-view v-else :user="user"></router-view>
        </template>
      </div>
    </main>
    <Toast />
  </div>
</template>

<script>
import { auth, db } from './firebase';
import { onAuthStateChanged, signOut } from 'firebase/auth';
import { doc, getDoc } from 'firebase/firestore';
import Login from './components/Login.vue';
import ThemeToggle from './components/ThemeToggle.vue';
import Toast from './components/Toast.vue';

export default {
  name: 'App',
  components: {
    Login,
    ThemeToggle,
    Toast
  },
  data() {
    return {
      user: null,
      loading: true
    }
  },
  created() {
    onAuthStateChanged(auth, async (user) => {
      if (user) {
        // Check if user is allowed
        const isAllowed = await this.checkUserAllowed(user.email);
        if (isAllowed) {
          this.user = user;
        } else {
          await this.logout("Access Denied: You are not on the allowed users list.");
        }
      } else {
        this.user = null;
      }
      this.loading = false;
    });
  },
  methods: {
    async checkUserAllowed(email) {
      if (!email) return false;
      try {
        const docRef = doc(db, "allowed_users", email);
        const docSnap = await getDoc(docRef);
        return docSnap.exists();
      } catch (error) {
        console.error("Error checking allowed user:", error);
        return false;
      }
    },
    async handleLogin() {
       // The onAuthStateChanged will handle the check.
    },
    async logout(message) {
      try {
        await signOut(auth);
        this.user = null;
        localStorage.removeItem('drive_access_token');
        if (message) {
            alert(message);
        }
      } catch (error) {
        console.error("Logout error:", error);
      }
    }
  }
}
</script>
