<template>
  <div class="bg-white dark:bg-gray-800 shadow overflow-hidden sm:rounded-lg">
    <div class="px-4 py-5 sm:px-6">
      <h3 class="text-lg leading-6 font-medium text-gray-900 dark:text-gray-100">
        User Settings
      </h3>
      <p class="mt-1 max-w-2xl text-sm text-gray-500 dark:text-gray-400">
        Manage your personal preferences.
      </p>
    </div>
    <div class="border-t border-gray-200 dark:border-gray-700">
      <dl>
        <div class="bg-gray-50 dark:bg-gray-700 px-4 py-5 sm:grid sm:grid-cols-3 sm:gap-4 sm:px-6">
          <dt class="text-sm font-medium text-gray-500 dark:text-gray-300">
            Full name
          </dt>
          <dd class="mt-1 text-sm text-gray-900 dark:text-white sm:mt-0 sm:col-span-2">
            {{ user.displayName || 'N/A' }}
          </dd>
        </div>
        <div class="bg-white dark:bg-gray-800 px-4 py-5 sm:grid sm:grid-cols-3 sm:gap-4 sm:px-6">
          <dt class="text-sm font-medium text-gray-500 dark:text-gray-300">
            Email address
          </dt>
          <dd class="mt-1 text-sm text-gray-900 dark:text-white sm:mt-0 sm:col-span-2">
            {{ user.email }}
          </dd>
        </div>
        <div class="bg-gray-50 dark:bg-gray-700 px-4 py-5 sm:grid sm:grid-cols-3 sm:gap-4 sm:px-6">
            <dt class="text-sm font-medium text-gray-500 dark:text-gray-300 self-center">
              Default Template
            </dt>
            <dd class="mt-1 text-sm text-gray-900 dark:text-white sm:mt-0 sm:col-span-2 flex items-center">
              <select
                v-model="defaultTemplateId"
                @change="savePreferences"
                class="mt-1 block w-full pl-3 pr-10 py-2 text-base border-gray-300 dark:border-gray-600 focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm rounded-md bg-white dark:bg-gray-600 dark:text-white"
              >
                  <option value="">&lt;None&gt;</option>
                  <option v-for="t in templates" :key="t.id" :value="t.id">
                      {{ t.name }}
                  </option>
              </select>
              <div v-if="saving" class="ml-4">
                  <svg class="animate-spin h-5 w-5 text-indigo-500" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                      <circle class="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" stroke-width="4"></circle>
                      <path class="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
              </div>
            </dd>
        </div>
      </dl>
    </div>
    <div v-if="message" class="px-4 py-3 bg-green-50 dark:bg-green-900/30 text-green-700 dark:text-green-200 sm:px-6">
      <p class="text-sm">{{ message }}</p>
    </div>
    <div v-if="error" class="px-4 py-3 bg-red-50 dark:bg-red-900/30 text-red-700 dark:text-red-200 sm:px-6">
      <p class="text-sm">{{ error }}</p>
    </div>
  </div>
</template>

<script>
import { db } from '../firebase';
import { collection, getDocs, query, orderBy, doc, getDoc, setDoc } from 'firebase/firestore';

export default {
  name: 'Settings',
  props: {
    user: {
      type: Object,
      required: true
    }
  },
  data() {
      return {
          templates: [],
          defaultTemplateId: '',
          saving: false,
          message: null,
          error: null
      }
  },
  async mounted() {
      await this.fetchTemplates();
      await this.fetchPreferences();
  },
  methods: {
      async fetchTemplates() {
        try {
            const q = query(collection(db, "templates"), orderBy("createdAt", "desc"));
            const snapshot = await getDocs(q);
            this.templates = snapshot.docs
                .map(doc => ({ id: doc.id, ...doc.data() }))
                .filter(t => !t.hidden);
        } catch (e) {
            console.error("Error fetching available templates:", e);
            this.error = "Failed to load templates.";
        }
      },
      async fetchPreferences() {
          try {
              const docRef = doc(db, "user_preferences", this.user.email);
              const docSnap = await getDoc(docRef);
              if (docSnap.exists()) {
                  this.defaultTemplateId = docSnap.data().defaultTemplateId || '';
              }
          } catch (e) {
              console.error("Error fetching preferences:", e);
              // Not critical
          }
      },
      async savePreferences() {
          this.saving = true;
          this.message = null;
          this.error = null;
          try {
              await setDoc(doc(db, "user_preferences", this.user.email), {
                  defaultTemplateId: this.defaultTemplateId
              }, { merge: true });
              this.message = "Preferences saved.";
              setTimeout(() => { this.message = null; }, 2000);
          } catch (e) {
              console.error("Error saving preferences:", e);
              this.error = "Failed to save preferences.";
          } finally {
              this.saving = false;
          }
      }
  }
}
</script>
