<script>
import { db, auth } from '../firebase';
import { doc, getDoc, collection, addDoc, getDocs, query, orderBy, updateDoc } from 'firebase/firestore';
import { GoogleAuthProvider, signInWithPopup } from 'firebase/auth';
import { processFile } from '../services/drive';
import { formatInteractionForClipboard, copyToClipboard } from '../utils/clipboard';
import { showToast } from '../utils/toast';

export default {
  name: 'Generate',
  props: {
    user: {
      type: Object,
      required: true
    }
  },
  data() {
    return {
      prompts: [],
      nextId: 2,
      response: '',
      loading: false,
      error: null,
      driveAccessToken: localStorage.getItem('drive_access_token'),
      generationCost: null,
      currentDocId: null,
      lastPayload: null,
      modelMeta: {},
      selectedModel: 'google/gemma-3-12b-it',
      availableTemplates: [],
      selectedTemplateId: '',
      models: [

        { id: 'google/gemma-3-4b-it', name: 'Gemma 3 4B' },
        { id: 'google/gemma-3n-e2b-it:free', name: 'Gemma 3n E2B IT (Free)' },
        { id: 'google/gemma-3n-e4b-it:free', name: 'Gemma 3n E4B IT (Free)' },
        { id: 'google/gemma-3-12b-it', name: 'Gemma 3 12B' },
        { id: 'google/gemma-3-12b-it:free', name: 'Gemma 3 12B (Free)' },
        { id: 'google/gemma-3-27b-it', name: 'Gemma 3 27B' },

        { id: 'qwen/qwen3-vl-8b-instruct', name: 'Qwen3 VL 8B Instruct' },
        { id: 'qwen/qwen3-vl-30b-a3b-instruct', name: 'Qwen3 VL 30B A3B Instruct' },
        { id: 'qwen/qwen3-vl-235b-a22b-instruct', name: 'Qwen3 VL 235B A22B Instruct' },

        { id: 'openai/gpt-3.5-turbo', name: 'GPT-3.5 Turbo' },
        { id: 'openai/gpt-4o', name: 'GPT-4o' },

        { id: 'anthropic/claude-3.5-sonnet', name: 'Claude 3.5 Sonnet' },
        { id: 'anthropic/claude-3-opus', name: 'Claude 3 Opus' },

        { id: 'google/gemini-3-flash-preview', name: 'Gemini 3 Flash Preview' },
        { id: 'google/gemini-3-pro-preview', name: 'Gemini 3 Pro Preview' },

      ],
      interactionStarred: false,
      interactionHidden: false,
      interactionTitle: '',
      conversationHistory: [] // Stores { type: 'user'|'assistant', ... }
    }
  },
  computed: {
    hasContent() {
        return this.prompts.some(p => p.text.trim().length > 0 || (p.attachments && p.attachments.length > 0));
    },
    currentModelInfo() {
        const meta = this.modelMeta[this.selectedModel];
        if (!meta) return null;

        const format = (p) => {
            const val = parseFloat(p) * 1000000;
            return `$${val.toFixed(2)}`;
        };

        return {
            pricing: {
                prompt: format(meta.pricing.prompt),
                completion: format(meta.pricing.completion)
            },
            capabilities: {
                image: meta.modalities.includes('image'),
                file: meta.modalities.includes('file') || meta.modalities.includes('pdf')
            }
        };
    },
    livePayload() {
        const messages = [];

        // 1. History
        this.conversationHistory.forEach(turn => {
            if (turn.type === 'user') {
                const parts = [];
                // Reconstruct parts logic for history items (simplified for preview)
                turn.prompts.forEach(p => {
                    if (p.text && p.text.trim()) parts.push({ type: "text", text: p.text });
                     if (p.attachments) {
                        p.attachments.forEach(att => {
                             if (att.type === 'application/vnd.google-apps.document') {
                                  parts.push({
                                      type: "file_url",
                                      file_url: {
                                          url: att.webViewLink || `https://docs.google.com/document/d/${att.docId}`,
                                          title: att.metadata && att.metadata.name ? att.metadata.name : att.name
                                      }
                                  });
                             } else if (att.type.startsWith('image/')) {
                                  parts.push({ type: "image_url", image_url: { url: att.content } });
                             }
                        });
                     }
                });
                if (parts.length > 0) messages.push({ role: 'user', content: parts });
            } else if (turn.type === 'assistant') {
                messages.push({ role: 'assistant', content: turn.text });
            }
        });

        // 2. Current Input
        const currentParts = [];
        this.prompts.forEach(p => {
             if (p.text.trim()) {
                  currentParts.push({ type: "text", text: p.text });
              }
              if (p.attachments && p.attachments.length > 0) {
                  p.attachments.forEach(att => {
                      if (att.type === 'application/vnd.google-apps.document') {
                          currentParts.push({
                              type: "file_url",
                              file_url: {
                                  url: att.webViewLink || `https://docs.google.com/document/d/${att.docId}`,
                                  title: att.metadata && att.metadata.name ? att.metadata.name : att.name,
                                  modified: att.metadata && att.metadata.modifiedTime ? att.metadata.modifiedTime : null
                              }
                          });
                      } else if (att.type.startsWith('image/')) {
                          currentParts.push({
                              type: "image_url",
                              image_url: {
                                  url: att.content // Base64
                              }
                          });
                      }
                  });
              }
        });

        if (currentParts.length > 0) {
            messages.push({ role: 'user', content: currentParts });
        }

        if (messages.length === 0) return null;

        return {
            "model": this.selectedModel,
            "messages": messages,
            "stream": true,
            "stream_options": { "include_usage": true }
        };
    },
    sanitizedPayload() {
        // Use livePayload if available, otherwise lastPayload (though we might not need lastPayload anymore for view)
        // Actually, let's just use livePayload for the view.
        // But wait, the user might want to see what was *actually* sent last time?
        // The request was "update it continuously as new inputs are specified".
        // So live preview implies current state.

        const source = this.livePayload;
        if (!source) return null;

        // Deep copy to avoid mutating original
        const payload = JSON.parse(JSON.stringify(source));

        if (payload.messages) {
            payload.messages.forEach(msg => {
                if (Array.isArray(msg.content)) {
                    msg.content.forEach(part => {
                        if (part.image_url && part.image_url.url && part.image_url.url.startsWith('data:')) {
                            const url = part.image_url.url;
                            part.image_url.url = url.substring(0, 30) + '...[truncated base64]...' + url.substring(url.length - 10);
                        }
                    });
                }
            });
        }
        return payload;
    },
    formattedPayload() {
        if (!this.sanitizedPayload) return '';
        const json = JSON.stringify(this.sanitizedPayload, null, 2);
        // Regex to find URLs and replace with <a> tags
        return json.replace(/("url":\s*")([^"]+)(")/g, (match, p1, p2, p3) => {
            if (p2.startsWith('http')) {
                 const cleanUrl = p2.replace('&export=download', '');
                 return `${p1}<a href="${cleanUrl}" target="_blank" class="text-blue-500 hover:underline">${cleanUrl}</a>${p3}`;
            }
            return match;
        });
    },
    isOwner() {
        if (!this.selectedTemplateId) return false;
        const current = this.availableTemplates.find(t => t.id === this.selectedTemplateId);
        return current && current.creator === this.user.email;
    }
  },
  async mounted() {
    this.fetchModelInfo();
    await this.fetchTemplates();

    if (this.$route.params.templateData) {
        // Use the passed template, ensuring we select it in dropdown if it exists there
        const t = this.$route.params.templateData;
        this.restoreTemplate(t);
        // If the template exists in our fetched list, set the dropdown value
        if (this.availableTemplates.find(x => x.id === t.id)) {
            this.selectedTemplateId = t.id;
        }
    } else {
        // Load default template if configured
        await this.loadDefaultTemplate();
    }
  },
  methods: {
    async loadDefaultTemplate() {
        try {
            const docRef = doc(db, "user_preferences", this.user.email);
            const docSnap = await getDoc(docRef);
            if (docSnap.exists()) {
                const prefs = docSnap.data();
                if (prefs.defaultTemplateId) {
                    const template = this.availableTemplates.find(t => t.id === prefs.defaultTemplateId);
                    if (template) {
                        this.selectedTemplateId = template.id;
                        this.restoreTemplate(template);
                    }
                }
            }
        } catch (e) {
            console.error("Error loading default template:", e);
        }
    },
    async fetchTemplates() {
        try {
            const q = query(collection(db, "templates"), orderBy("createdAt", "desc"));
            const snapshot = await getDocs(q);
            // Filter non-hidden templates
            this.availableTemplates = snapshot.docs
                .map(doc => ({ id: doc.id, ...doc.data() }))
                .filter(t => !t.hidden);
        } catch (e) {
            console.error("Error fetching available templates:", e);
        }
    },
    handleTemplateSelect() {
        if (!this.selectedTemplateId) {
            this.resetForm();
            return;
        }
        const template = this.availableTemplates.find(t => t.id === this.selectedTemplateId);
        if (template) {
            this.restoreTemplate(template);
        }
    },
    resetForm() {
        this.prompts = [];
        this.nextId = 1;
        this.response = '';
        this.conversationHistory = [];
        this.error = null;
        this.selectedModel = 'google/gemma-3-12b-it';
        this.currentDocId = null;
        this.generationCost = null;
    },
    addInput() {
        this.prompts.push({ id: this.nextId++, text: '', attachments: [], isDragging: false });
    },
    removeInput(index) {
        this.prompts.splice(index, 1);
    },
    removeAttachment(promptIndex, attachmentIndex) {
        this.prompts[promptIndex].attachments.splice(attachmentIndex, 1);
    },
    handleDrop(event, index) {
        this.prompts[index].isDragging = false;
        const files = event.dataTransfer.files;
        if (files.length) {
            this.processFiles(files, index);
            return;
        }

        // Try to extract image URL (from browser drag-and-drop)
        const html = event.dataTransfer.getData('text/html');
        let imageUrl = event.dataTransfer.getData('text/uri-list'); // Fallback

        if (html) {
             const parser = new DOMParser();
             const doc = parser.parseFromString(html, 'text/html');
             const img = doc.querySelector('img');
             if (img && img.src) {
                 imageUrl = img.src;
             }
        }

        if (imageUrl) {
             if (this.currentModelInfo && !this.currentModelInfo.capabilities.image) {
                 this.error = `The selected model '${this.models.find(m => m.id === this.selectedModel)?.name}' does not support image input.`;
                 setTimeout(() => { this.error = null; }, 5000);
                 return;
             }

             // Attempt to upload to Drive by converting to File
             this.urlToFile(imageUrl).then(file => {
                 if (file) {
                     this.processFiles([file], index);
                 } else {
                     // Fallback if fetch fails (e.g. CORS)
                     this.error = "Could not retrieve dropped image for upload. Please upload the file directly.";
                     setTimeout(() => { this.error = null; }, 5000);
                 }
             });
        }
    },
    async urlToFile(url) {
        try {
            const res = await fetch(url);
            const blob = await res.blob();
            const mime = blob.type;
            const ext = mime.split('/')[1] || 'png';
            const filename = `dropped_image_${Date.now()}.${ext}`;
            return new File([blob], filename, { type: mime });
        } catch (e) {
            console.warn("CORS or network error fetching image for upload:", e);
            return null;
        }
    },
    handlePaste(event, index) {
        const items = (event.clipboardData || event.originalEvent.clipboardData).items;
        for (const item of items) {
            if (item.kind === 'file') {
                const file = item.getAsFile();
                this.processFiles([file], index);
            }
        }
    },
    async processFiles(fileList, index) {
        if (!this.currentModelInfo) return;

        // Ensure we have a Drive Token
        if (!this.driveAccessToken) {
            const token = await this.authorizeDrive();
            if (!token) return;
        }

        for (const file of fileList) {
            const isImage = file.type.startsWith('image/');
            const supportsImage = this.currentModelInfo.capabilities.image;
            const supportsFile = this.currentModelInfo.capabilities.file;

            if (isImage && !supportsImage) {
                this.error = `The selected model '${this.models.find(m => m.id === this.selectedModel)?.name}' does not support image input.`;
                setTimeout(() => { this.error = null; }, 5000);
                continue;
            }

            if (!isImage && !supportsFile) {
                this.error = `The selected model '${this.models.find(m => m.id === this.selectedModel)?.name}' does not support file input.`;
                setTimeout(() => { this.error = null; }, 5000);
                continue;
            }

            // Add placeholder
            const tempId = Date.now() + Math.random();
            const placeholder = {
                id: tempId,
                name: file.name,
                type: file.type,
                isUploading: true
            };
            this.prompts[index].attachments.push(placeholder);

            // Set loading state
            console.log(`Starting upload for ${file.name}, tempId: ${tempId}`);
            try {
                const result = await processFile(file, this.driveAccessToken);
                console.log(`Upload finished for ${file.name}, result:`, result);

                // Find placeholder and replace
                const attIndex = this.prompts[index].attachments.findIndex(a => a.id === tempId);
                console.log(`Found placeholder at index: ${attIndex}`);

                if (attIndex !== -1) {
                    this.prompts[index].attachments.splice(attIndex, 1, {
                        id: result.id || tempId, // Keep ID stable or use Drive ID
                        name: result.name, // Hash
                        originalName: result.originalName,
                        type: result.type,
                        content: result.webContentLink,
                        previewUrl: URL.createObjectURL(file), // Local preview
                        webViewLink: result.webViewLink,
                        thumbnailLink: result.thumbnailLink,
                        isUploading: false
                    });
                    console.log("Replaced placeholder with result");
                } else {
                    console.warn("Placeholder not found!");
                }
            } catch (e) {
                console.error("Upload failed", e);
                // Remove placeholder on error
                const attIndex = this.prompts[index].attachments.findIndex(a => a.id === tempId);
                if (attIndex !== -1) {
                    this.prompts[index].attachments.splice(attIndex, 1);
                }

                // Check if error is related to permissions or auth
                const errMsg = e.message || '';
                if (errMsg.includes('403') || errMsg.includes('permission') || errMsg.includes('401') || errMsg.includes('Unauthorized')) {
                     // Force re-auth with consent
                     const token = await this.authorizeDrive(true);
                     if (token) {
                         // Add placeholder again for retry
                         this.prompts[index].attachments.push(placeholder);
                         try {
                               // Retry upload once
                               const result = await processFile(file, token);
                               // Replace again (find by ID)
                               const retryIndex = this.prompts[index].attachments.findIndex(a => a.id === tempId);
                                if (retryIndex !== -1) {
                                     this.prompts[index].attachments.splice(retryIndex, 1, {
                                         name: result.name || result.originalName, // Ensure name is set (result.name is hash usually)
                                         originalName: result.originalName,
                                         type: result.type,
                                         content: result.webContentLink,
                                         previewUrl: URL.createObjectURL(file), // Local preview
                                         webViewLink: result.webViewLink,
                                         thumbnailLink: result.thumbnailLink,
                                         isUploading: false
                                     });
                                }
                               continue;
                         } catch (retryErr) {
                             // Remove placeholder (find by ID)
                             const retryIndex = this.prompts[index].attachments.findIndex(a => a.id === tempId);
                             if (retryIndex !== -1) this.prompts[index].attachments.splice(retryIndex, 1);

                             this.error = "Failed to upload file after re-auth: " + retryErr.message;
                         }
                     }
                } else {
                    this.error = "Failed to upload file: " + e.message;
                }
            }
        }
    },
    async getApiKey() {
        const userDocRef = doc(db, "allowed_users", this.user.email);
        const userDocSnap = await getDoc(userDocRef);

        if (!userDocSnap.exists()) {
            throw new Error("User record not found.");
        }

        const apiKey = userDocSnap.data().openrouter_api_key;
        if (!apiKey) {
            throw new Error("OpenRouter API Key not found. Please contact administrator.");
        }
        return apiKey;
    },
    async authorizeDrive(forceConsent = false) {
        const provider = new GoogleAuthProvider();
        provider.addScope('https://www.googleapis.com/auth/documents.readonly');
        provider.addScope('https://www.googleapis.com/auth/drive');

        if (forceConsent) {
            provider.setCustomParameters({
                prompt: 'consent'
            });
        }
        try {
            const result = await signInWithPopup(auth, provider);
            const credential = GoogleAuthProvider.credentialFromResult(result);
            this.driveAccessToken = credential.accessToken;
            localStorage.setItem('drive_access_token', credential.accessToken);
            return this.driveAccessToken;
        } catch (error) {
            console.error("Error authorizing Drive:", error);
            this.error = "Failed to authorize Google Drive access: " + error.message;
            return null;
        }
    },
    async fetchDocContent(docId) {
        if (!this.driveAccessToken) {
            const token = await this.authorizeDrive();
            if (!token) return null;
        }

        try {
            const response = await fetch(`https://docs.googleapis.com/v1/documents/${docId}`, {
                headers: {
                    'Authorization': `Bearer ${this.driveAccessToken}`
                }
            });

            if (!response.ok) {
                if (response.status === 401 || response.status === 403) {
                    // Token might be expired or invalid, try re-auth once
                    const newToken = await this.authorizeDrive();
                    if (newToken) {
                        return this.fetchDocContent(docId);
                    }
                }
                throw new Error(`Failed to fetch document: ${response.statusText}`);
            }

            const data = await response.json();
            return this.parseDocContent(data);
        } catch (e) {
            this.error = e.message;
            return null;
        }
    },
    parseDocContent(data) {
        if (!data || !data.body || !data.body.content) return [];

        const parts = [];
        let currentText = '';

        const flushText = () => {
            if (currentText.trim()) {
                parts.push({ type: 'text', content: currentText });
            }
            currentText = '';
        };

        data.body.content.forEach(element => {
            if (element.paragraph) {
                // Handle Headers
                const styleType = element.paragraph.paragraphStyle?.namedStyleType;
                let prefix = '';
                let suffix = '\n'; // Paragraph break

                if (styleType === 'HEADING_1') prefix = '# ';
                else if (styleType === 'HEADING_2') prefix = '## ';
                else if (styleType === 'HEADING_3') prefix = '### ';
                else if (styleType === 'HEADING_4') prefix = '#### ';
                else if (styleType === 'HEADING_5') prefix = '##### ';
                else if (styleType === 'HEADING_6') prefix = '###### ';

                // Handle Lists (Bullets)
                if (element.paragraph.bullet) {
                   prefix = '- ' + prefix;
                }

                currentText += prefix;

                element.paragraph.elements.forEach(el => {
                    if (el.textRun && el.textRun.content) {
                        let content = el.textRun.content;
                        const style = el.textRun.textStyle;

                        // Handle Bold/Italic
                        // Note: This simple approach handles nested styles poorly (e.g. bold+italic),
                        // but is sufficient for basic formatting.
                        if (style) {
                            if (style.bold && content.trim()) content = `**${content}**`;
                            if (style.italic && content.trim()) content = `*${content}*`;
                        }

                        currentText += content;
                    } else if (el.inlineObjectElement) {
                        // Flush text before image
                        flushText();

                        const objectId = el.inlineObjectElement.inlineObjectId;
                        const embeddedObject = data.inlineObjects[objectId]?.inlineObjectProperties?.embeddedObject;

                        // Extract Image URL
                        // Note: embeddedObject.imageProperties.contentUri is valid for ~30mins
                        if (embeddedObject && embeddedObject.imageProperties && embeddedObject.imageProperties.contentUri) {
                             parts.push({
                                 type: 'image',
                                 source: embeddedObject.imageProperties.contentUri,
                                 name: 'Embedded Image' // Could try to get title if available
                             });
                        }
                    }
                });

                currentText += suffix;
            }
        });

        flushText();

        return parts;
    },
    async fetchDocMetadata(docId) {
        if (!this.driveAccessToken) {
           // Wait for auth or just return null (UI will handle missing metadata)
           return null;
        }

        try {
            const response = await fetch(`https://www.googleapis.com/drive/v3/files/${docId}?fields=name,owners,modifiedTime,webViewLink,webContentLink,thumbnailLink`, {
                headers: {
                    'Authorization': `Bearer ${this.driveAccessToken}`
                }
            });

            if (!response.ok) {
                 console.error("Failed to fetch doc metadata", response.statusText);
                 return null;
            }

            return await response.json();
        } catch (e) {
            console.error("Error fetching metadata:", e);
            return null;
        }
    },
    async checkForDocLinks(index, event) {
        // Use event value if available, otherwise fall back to model
        const text = event && event.target ? event.target.value : this.prompts[index].text;

        if (!text) return;

        const googleDocRegex = /https:\/\/docs\.google\.com\/document\/d\/([a-zA-Z0-9-_]+)[^ \n]*/g;
        let match;

        const matches = [];
        googleDocRegex.lastIndex = 0;

        while ((match = googleDocRegex.exec(text)) !== null) {
            matches.push({
                full: match[0],
                id: match[1],
                index: match.index
            });
        }

        if (matches.length > 0) {
            // First match wins for "only content of that chunk" rule?
            // The user said "When a google doc is pasted, it should be the only content of that chunk"
            // So if we find a link, we replace the whole text? Or just that link?
            // "the textarea should disappear and be replaced with a clickable URL" implies the chunk becomes a "Doc Chunk"

            // We'll take the first match, clear the text, and add the attachment with metadata.
            const m = matches[0];

            // Fetch metadata
            if (!this.driveAccessToken) {
                 // Try to auth internally or just wait?
                 // If we auto-auth here, it might popup. But user just pasted.
                 // Let's try to get token if possible, or trigger auth flow if needed?
                 // For now, assume token exists or will be refreshed. The user is logged in.
            }

            const metadata = await this.fetchDocMetadata(m.id);

            this.prompts[index].text = ''; // Clear text as requested
            this.prompts[index].attachments = [{ // Replace any existing attachments? "only content"
                name: metadata ? metadata.name : 'Google Doc',
                type: 'application/vnd.google-apps.document',
                docId: m.id,
                content: null,
                metadata: metadata // Store full metadata
            }];
        }
    },
    async fetchModelInfo() {
        try {
            const apiKey = await this.getApiKey();
            const res = await fetch("https://openrouter.ai/api/v1/models", {
                headers: {
                    "Authorization": `Bearer ${apiKey}`
                }
            });

            if (res.ok) {
                const data = await res.json();
                const meta = {};
                data.data.forEach(m => {
                    meta[m.id] = {
                        pricing: m.pricing,
                        modalities: m.architecture?.input_modalities || []
                    };
                });
                this.modelMeta = meta;
            }
        } catch (e) {
            console.error("Failed to fetch model info", e);
        }
    },
    async queryLLM() {
      if (!this.hasContent) return;

      this.loading = true;
      this.error = null;
      this.generationCost = null;
      this.currentDocId = null;

      // Reset legacy tracking vars for the new turn
      this.interactionStarred = false;
      this.interactionHidden = false;
      this.interactionTitle = '';

      const newUserParts = [];

      try {
          // Process all prompts and attachments
          for (const p of this.prompts) {
              if (p.text.trim()) {
                  newUserParts.push({ type: "text", text: p.text });
              }
              if (p.attachments && p.attachments.length > 0) {
                  for (const att of p.attachments) {
                      if (att.type === 'application/vnd.google-apps.document') {
                          // Fetch doc content
                          const docParts = await this.fetchDocContent(att.docId);

                          if (docParts && docParts.length > 0) {
                              docParts.forEach(part => {
                                  if (part.type === 'text') {
                                      newUserParts.push({ type: "text", text: part.content });
                                  } else if (part.type === 'image') {
                                      newUserParts.push({
                                          type: "image_url",
                                          image_url: {
                                              url: part.source
                                          }
                                      });
                                  }
                              });
                          } else {
                               if (this.error) throw new Error(this.error);
                          }
                      } else if (att.type.startsWith('image/')) {
                          newUserParts.push({
                              type: "image_url",
                              image_url: {
                                  url: att.content // Base64
                              }
                          });
                      }
                  }
              }
          }

          if (newUserParts.length === 0) {
              this.loading = false;
              return;
          }

          // Add User Turn to History
          this.conversationHistory.push({
              type: 'user',
              prompts: JSON.parse(JSON.stringify(this.prompts)), // Store UI state for display
              content: newUserParts // Store processed parts for context
          });

          // Add Assistant Turn Placeholder
          const assistantTurn = {
              type: 'assistant',
              text: '',
              model: this.selectedModel,
              cost: 0,
              docId: null,
              starred: false,
              hidden: false,
              title: ''
          };
          this.conversationHistory.push(assistantTurn);

          // Build Messages for API
          const messages = [];
          this.conversationHistory.forEach(turn => {
              if (turn.type === 'user') {
                  if (turn.content && turn.content.length) {
                       messages.push({ role: 'user', content: turn.content });
                  }
              } else if (turn.type === 'assistant') {
                  // Exclude the current empty placeholder from request context
                  if (turn !== assistantTurn && turn.text) {
                       messages.push({ role: 'assistant', content: turn.text });
                  }
              }
          });

        // 1. Get API Key
        const apiKey = await this.getApiKey();

        // 2. Make Request
        const requestBody = {
            "model": this.selectedModel,
            "messages": messages,
            "stream": true,
            "stream_options": { "include_usage": true }
        };
        this.lastPayload = requestBody;

        const res = await fetch("https://openrouter.ai/api/v1/chat/completions", {
          method: "POST",
          headers: {
            "Authorization": `Bearer ${apiKey}`,
            "Content-Type": "application/json"
          },
          body: JSON.stringify(requestBody)
        });

        if (!res.ok) {
            const errData = await res.json();
            throw new Error(errData.error?.message || "Failed to fetch response from OpenRouter");
        }

        // 3. Handle Stream
        const reader = res.body.getReader();
        const decoder = new TextDecoder("utf-8");

        for (;;) {
          const { done, value } = await reader.read();
          if (done) break;

          const chunk = decoder.decode(value);
          const lines = chunk.split("\n");

          for (const line of lines) {
            if (line.startsWith("data: ")) {
                const dataStr = line.slice(6);
                if (dataStr === "[DONE]") continue;
                try {
                    const data = JSON.parse(dataStr);

                    // Handle Content
                    const content = data.choices[0]?.delta?.content || "";
                    assistantTurn.text += content;
                    this.response = assistantTurn.text; // Legacy/Display sync

                    // Handle Usage
                    if (data.usage) {
                        const promptTokens = data.usage.prompt_tokens || 0;
                        const completionTokens = data.usage.completion_tokens || 0;
                        const pricing = this.modelMeta[this.selectedModel]?.pricing;

                        if (pricing) {
                            const promptCost = promptTokens * parseFloat(pricing.prompt);
                            const completionCost = completionTokens * parseFloat(pricing.completion);
                            assistantTurn.cost = (promptCost + completionCost).toFixed(6);
                            this.generationCost = assistantTurn.cost;
                        }
                    }
                } catch (e) {
                    // console.error("Error parsing stream chunk", e);
                }
            }
          }
        }

        // 4. Log to Firebase
        try {
            // Construct Logical Payload for Logging (preserves file_url)
            const logicalMessages = [];
            this.conversationHistory.forEach(turn => {
                if (turn.type === 'user') {
                    const parts = [];
                    // Reconstruct from turn.prompts to keep file_url
                    if (turn.prompts) {
                        turn.prompts.forEach(p => {
                            if (p.text && p.text.trim()) {
                                parts.push({ type: "text", text: p.text });
                            }
                            if (p.attachments) {
                                p.attachments.forEach(att => {
                                    if (att.type === 'application/vnd.google-apps.document') {
                                        parts.push({
                                            type: "file_url",
                                            file_url: {
                                                url: att.webViewLink || `https://docs.google.com/document/d/${att.docId}`,
                                                title: att.metadata && att.metadata.name ? att.metadata.name : att.name
                                            }
                                        });
                                    } else if (att.type.startsWith('image/')) {
                                        parts.push({
                                            type: "image_url",
                                            image_url: {
                                                url: att.content // Reference base64/url
                                            }
                                        });
                                    }
                                });
                            }
                        });
                    }
                    if (parts.length > 0) logicalMessages.push({ role: 'user', content: parts });
                } else if (turn.type === 'assistant') {
                    // Exclude current streaming assistant turn if empty, though here we want to log what we HAVE so far
                    if (turn.text) {
                        logicalMessages.push({ role: 'assistant', content: turn.text });
                    }
                }
            });

            const logPayload = {
                model: this.selectedModel,
                messages: logicalMessages,
                stream: true,
                stream_options: { include_usage: true }
            };

            // Update assistant turn with final data
            const assistantTurn = this.conversationHistory[this.conversationHistory.length - 1];
            assistantTurn.text = this.response;
            assistantTurn.model = this.selectedModel;
            const cost = assistantTurn.cost; // Retrieve final cost calculated during stream

            // Calculate total cost (cumulative of all turns)
            const totalCost = this.conversationHistory.reduce((acc, turn) => {
                return acc + (parseFloat(turn.cost) || 0);
            }, 0);

            // Log for debugging
            console.log('Cumulative Cost Calculation:', {
                currentCost: cost,
                historyLength: this.conversationHistory.length,
                totalCost: totalCost,
                historyCosts: this.conversationHistory.map(t => t.cost)
            });

            const docRef = await addDoc(collection(db, "interaction_logs"), {
                timestamp: new Date(),
                user: this.user.email,
                payload: JSON.parse(JSON.stringify(logPayload)),
                prompts: JSON.parse(JSON.stringify(this.prompts.map(p => ({
                    text: p.text,
                    attachments: p.attachments.map(a => ({
                        name: a.name,
                        originalName: a.originalName,
                        type: a.type,
                        docId: a.docId,
                        metadata: a.metadata,
                        content: a.content,
                        webViewLink: a.webViewLink,
                        thumbnailLink: a.thumbnailLink
                    }))
                })))),
                response: assistantTurn.text,
                cost: parseFloat(totalCost || 0), // Store cumulative cost
                model: this.selectedModel,
                conversation_history: JSON.parse(JSON.stringify(this.conversationHistory)) // Store full history
            });
            assistantTurn.docId = docRef.id;
            this.currentDocId = docRef.id;
        } catch (e) {
            console.error("Failed to log interaction", e);
            this.error = "Failed to save interaction log: " + e.message;
            showToast("Failed to save interaction log", "error");
        }

        // Reset Prompts for next input
        this.prompts = [];
        this.nextId = 1;

      } catch (err) {
        this.error = err.message;
      } finally {
        this.loading = false;
      }
    },

    async saveTemplate(isNew = false) {
        const name = prompt("Enter a name for this template:", isNew ? '' : (this.availableTemplates.find(t => t.id === this.selectedTemplateId)?.name || ''));
        if (!name) return;

        try {
            const rawPrompts = this.prompts.map(p => ({
                text: p.text,
                attachments: p.attachments.map(a => ({
                    name: a.name,
                    originalName: a.originalName,
                    type: a.type,
                    docId: a.docId,
                    metadata: a.metadata,
                    content: a.content,
                    webViewLink: a.webViewLink,
                    thumbnailLink: a.thumbnailLink
                }))
            }));

            // Remove undefined values which Firestore doesn't support
            const templatePrompts = JSON.parse(JSON.stringify(rawPrompts));

            const templateData = {
                name: name,
                creator: this.user.email,
                createdAt: new Date(),
                model: this.selectedModel,
                prompts: templatePrompts
            };

            await addDoc(collection(db, "templates"), templateData);

            // Refresh list
            await this.fetchTemplates();
            // Automatically select the new template if we just created it?
            // Or just alert?

            alert("Template created successfully!");
        } catch (e) {
            console.error("Error saving template:", e);
            this.error = "Failed to save template: " + e.message;
        }
    },
    async updateTemplate() {
        if (!this.selectedTemplateId || !this.isOwner) return;

        if (!confirm("Are you sure you want to update the current template with this configuration?")) return;

        try {
            const rawPrompts = this.prompts.map(p => ({
                text: p.text,
                attachments: p.attachments.map(a => ({
                    name: a.name,
                    originalName: a.originalName,
                    type: a.type,
                    docId: a.docId,
                    metadata: a.metadata,
                    content: a.content,
                    webViewLink: a.webViewLink,
                    thumbnailLink: a.thumbnailLink
                }))
            }));

            const templatePrompts = JSON.parse(JSON.stringify(rawPrompts));

            const templateRef = doc(db, "templates", this.selectedTemplateId);
            await updateDoc(templateRef, {
                model: this.selectedModel,
                prompts: templatePrompts,
                updatedAt: new Date()
            });

             // Refresh list (just in case)
            await this.fetchTemplates();

            alert("Template updated successfully!");
        } catch (e) {
             console.error("Error updating template:", e);
             this.error = "Failed to update template: " + e.message;
        }
    },
    async restoreTemplate(data) {
        this.selectedModel = data.model;

        // Restore History
        if (data.conversation_history) { // Check for new field first
            this.conversationHistory = data.conversation_history;
        } else if (data.conversationHistory) { // Fallback for legacy casing
            this.conversationHistory = data.conversationHistory;
        } else {
            this.conversationHistory = []; // Default if no history found
        }

        // Restore Current Prompts (if any provided, else default to empty)
        if (data.prompts && data.prompts.length > 0) {
            this.prompts = data.prompts.map((p, i) => ({
                id: i + 1,
                text: p.text,
                attachments: p.attachments || [],
                isDragging: false
            }));
        } else {
             this.prompts = [];
        }
        this.nextId = this.prompts.length + 1;

        // Restore/Fetch metadata for Google Docs and Images in current prompts
        for (const p of this.prompts) {
            await this.enrichItemAttachments(p);
        }

        // Restore/Fetch metadata for history items
        for (const turn of this.conversationHistory) {
             if (turn.type === 'user' && turn.prompts) {
                 for (const p of turn.prompts) {
                     await this.enrichItemAttachments(p);
                 }
             }
        }
    },
    async enrichItemAttachments(item) {
        if (!item.attachments) return;

        for (const att of item.attachments) {
            let shouldFetchMeta = false;
            let targetId = att.docId;

            // Case 1: Google Doc
            if (att.type === 'application/vnd.google-apps.document') {
                    shouldFetchMeta = true;
            }
            // Case 2: Image from Drive (check for ID or extract from URL)
            else if (att.type.startsWith('image/') || att.type === 'image/url') {
                    if (!targetId && att.content && typeof att.content === 'string') {
                        targetId = this.extractDriveId(att.content);
                        if (targetId) {
                            att.docId = targetId; // Save extracted ID
                        }
                    }
                    if (targetId) {
                        shouldFetchMeta = true;
                    }
            }

            if (shouldFetchMeta && targetId) {
                    // Always try to refresh metadata to get fresh links (especially thumbnails)
                    const meta = await this.fetchDocMetadata(targetId);
                    if (meta) {
                        this.$set(att, 'metadata', meta);
                        if (meta.thumbnailLink) this.$set(att, 'thumbnailLink', meta.thumbnailLink);
                        if (meta.webViewLink) this.$set(att, 'webViewLink', meta.webViewLink);
                        if (meta.webContentLink) this.$set(att, 'content', meta.webContentLink);
                    }

                    // Load Preview Blob
                    if (att.type.startsWith('image/') || att.type === 'image/url') {
                        this.loadDriveImagePreview(att);
                    }
            }
        }
    },
    extractDriveId(url) {
        if (!url) return null;
        let match = url.match(/\/d\/([a-zA-Z0-9-_]+)/);
        if (match) return match[1];
        match = url.match(/id=([a-zA-Z0-9-_]+)/);
        if (match) return match[1];
        return null;
    },
    async loadDriveImagePreview(att) {
        // Try to fetch image data with auth token
        const id = att.docId || this.extractDriveId(att.content);
        if (!id) return;

        try {
            if (!this.driveAccessToken) {
                 await this.authorizeDrive(); // Silent or will fail
            }
            if (!this.driveAccessToken) return;

            const res = await fetch(`https://www.googleapis.com/drive/v3/files/${id}?alt=media`, {
                 headers: { 'Authorization': `Bearer ${this.driveAccessToken}` }
            });

            if (res.ok) {
                const blob = await res.blob();
                const url = URL.createObjectURL(blob);
                this.$set(att, 'previewUrl', url);
            }
        } catch(e) {
            console.warn("Failed to load drive image preview", e);
        }
    },
    async toggleInteractionStar(turn) {
        if (!turn || !turn.docId) return;
        const newValue = !turn.starred;
        turn.starred = newValue;
        try {
            await updateDoc(doc(db, "interaction_logs", turn.docId), { starred: newValue });
        } catch (e) {
            console.error("Error toggling star:", e);
            turn.starred = !newValue; // Revert
            showToast("Failed to update star status: " + e.message, "error");
        }
    },
    async toggleInteractionHide(turn) {
        if (!turn || !turn.docId) return;
        const newValue = !turn.hidden;
        turn.hidden = newValue;
        try {
            await updateDoc(doc(db, "interaction_logs", turn.docId), { hidden: newValue });
        } catch (e) {
            console.error("Error toggling hide:", e);
            turn.hidden = !newValue; // Revert
            showToast("Failed to update hide status: " + e.message, "error");
        }
    },
    async saveInteractionTitle(turn) {
        if (!turn || !turn.docId) return;
        try {
            await updateDoc(doc(db, "interaction_logs", turn.docId), { title: turn.title });
        } catch (e) {
            console.error("Error saving title:", e);
            showToast("Failed to save title: " + e.message, "error");
        }
    },
    async copyInteraction(turn) {
        if (!turn || !turn.text) return;

        const interaction = {
            id: turn.docId || 'temp',
            timestamp: new Date(),
            model: turn.model || this.selectedModel,
            response: turn.text
        };

        const text = formatInteractionForClipboard(interaction);
        const success = await copyToClipboard(text);
        if (success) {
            // Optional: visual feedback
        }
    },
    isLastTurn(index) {
        return index === this.conversationHistory.length - 1;
    },
    deleteHistoryTurn(index) {
        // For deleting assistant turn (output)
        // Check if consistent
        if (index !== this.conversationHistory.length - 1) return;

        // 1. Remove Assistant Turn
        this.conversationHistory.splice(index, 1);

        // 2. Check if new last turn is User Turn
        const lastTurnIndex = this.conversationHistory.length - 1;
        if (lastTurnIndex >= 0) {
            const lastTurn = this.conversationHistory[lastTurnIndex];
            if (lastTurn && lastTurn.type === 'user') {
                // 3. Pop User Turn to Prompts
                // Map history prompts back to editable prompts
                this.prompts = lastTurn.prompts.map((p, i) => ({
                    id: this.nextId + i,
                    text: p.text,
                    attachments: p.attachments || [],
                    isDragging: false
                }));
                this.nextId += lastTurn.prompts.length;

                // Remove from history
                this.conversationHistory.splice(lastTurnIndex, 1);
            }
        }
    }
  }
}
</script>
