<template>
  <div class="bg-white dark:bg-gray-900 shadow sm:rounded-lg overflow-hidden border border-gray-200 dark:border-gray-700">
    <div class="px-4 py-5 sm:px-6 flex justify-between items-center bg-white dark:bg-gray-800 border-b border-gray-200 dark:border-gray-700">
      <div>
        <h3 class="text-lg leading-6 font-medium text-gray-900 dark:text-white">
          Saved Templates
        </h3>
        <p class="mt-1 max-w-2xl text-sm text-gray-500 dark:text-gray-400">
          Select and manage your templates.
        </p>
      </div>
      <div class="flex items-center space-x-4">
        <label class="flex items-center cursor-pointer select-none">
           <div class="relative">
             <input type="checkbox" v-model="showHidden" class="sr-only" />
             <div class="block w-10 h-6 bg-gray-200 dark:bg-gray-700 rounded-full transition-colors ease-in-out duration-200"></div>
             <div class="dot absolute left-1 top-1 bg-white w-4 h-4 rounded-full transition transform duration-200" :class="{'translate-x-4 bg-indigo-500': showHidden}"></div>
           </div>
           <div class="ml-3 text-sm text-gray-700 dark:text-gray-300 font-medium">
             Show Hidden
           </div>
        </label>
      </div>
    </div>

    <div class="bg-white dark:bg-gray-900">
      <div v-if="loading" class="text-center py-8">
        <p class="text-sm text-gray-500 dark:text-gray-400 animate-pulse">Loading templates...</p>
      </div>

      <div v-else>
         <!-- Table Header -->
         <div class="grid grid-cols-12 gap-4 px-4 py-3 bg-gray-50 dark:bg-gray-800/50 text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider border-b border-gray-200 dark:border-gray-700 backdrop-blur-sm">
             <div class="col-span-4 cursor-pointer hover:text-gray-700 dark:hover:text-gray-200 flex items-center group transition-colors" @click="setSort('name')">
                 Name
                 <span v-if="sortKey === 'name'" class="ml-1 text-indigo-500 dark:text-indigo-400">{{ sortDesc ? '↓' : '↑' }}</span>
                 <span v-else class="ml-1 opacity-0 group-hover:opacity-50">↓</span>
             </div>
             <div class="col-span-3 cursor-pointer hover:text-gray-700 dark:hover:text-gray-200 flex items-center group transition-colors" @click="setSort('creator')">
                 Author
                 <span v-if="sortKey === 'creator'" class="ml-1 text-indigo-500 dark:text-indigo-400">{{ sortDesc ? '↓' : '↑' }}</span>
                 <span v-else class="ml-1 opacity-0 group-hover:opacity-50">↓</span>
             </div>
             <div class="col-span-3 cursor-pointer hover:text-gray-700 dark:hover:text-gray-200 flex items-center group transition-colors" @click="setSort('updatedAt')">
                 Last Modified
                 <span v-if="sortKey === 'updatedAt'" class="ml-1 text-indigo-500 dark:text-indigo-400">{{ sortDesc ? '↓' : '↑' }}</span>
                 <span v-else class="ml-1 opacity-0 group-hover:opacity-50">↓</span>
             </div>
             <div class="col-span-2 text-right">Actions</div>
         </div>

         <!-- Table Body -->
         <ul class="divide-y divide-gray-200 dark:divide-gray-800">
            <li v-for="template in filteredTemplates" :key="template.id"
                class="grid grid-cols-12 gap-4 px-4 py-4 items-center hover:bg-gray-50 dark:hover:bg-gray-800 transition duration-150 ease-in-out cursor-default group">
                 <div class="col-span-4 cursor-pointer" @click="selectTemplate(template)">
                     <div class="font-medium text-indigo-600 dark:text-indigo-400 truncate group-hover:text-indigo-700 dark:group-hover:text-indigo-300 transition-colors">
                        {{ template.name }}
                     </div>
                     <span class="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-gray-100 dark:bg-gray-800 text-gray-800 dark:text-gray-300 mt-1 border border-gray-200 dark:border-gray-700">
                         {{ template.model }}
                     </span>
                 </div>

                 <div class="col-span-3 text-sm text-gray-600 dark:text-gray-400 group-hover:text-gray-900 dark:group-hover:text-gray-300 transition-colors">
                     {{ template.creator || 'Unknown' }}
                 </div>

                 <div class="col-span-3 text-sm text-gray-600 dark:text-gray-400 group-hover:text-gray-900 dark:group-hover:text-gray-300 transition-colors">
                     {{ formatDate(template.updatedAt || template.createdAt) }}
                 </div>

                 <div class="col-span-2 text-right opacity-100 sm:opacity-0 sm:group-hover:opacity-100 transition-opacity">
                     <button @click.stop="toggleHidden(template)" class="inline-flex items-center px-3 py-1.5 border border-gray-300 dark:border-gray-600 shadow-sm text-xs font-medium rounded-md text-gray-700 dark:text-gray-200 bg-white dark:bg-gray-700 hover:bg-gray-50 dark:hover:bg-gray-600 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500 transition-colors">
                         {{ template.hidden ? 'Unhide' : 'Hide' }}
                     </button>
                 </div>
            </li>
         </ul>

         <div v-if="filteredTemplates.length === 0" class="text-center py-12">
             <svg class="mx-auto h-12 w-12 text-gray-400 dark:text-gray-600" fill="none" viewBox="0 0 24 24" stroke="currentColor" aria-hidden="true">
                 <path vector-effect="non-scaling-stroke" stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M9 13h6m-3-3v6m-9 1V7a2 2 0 012-2h6l2 2h6a2 2 0 012 2v8a2 2 0 01-2 2H5a2 2 0 01-2-2z" />
             </svg>
             <h3 class="mt-2 text-sm font-medium text-gray-900 dark:text-gray-100">No templates found</h3>
             <p class="mt-1 text-sm text-gray-500 dark:text-gray-400">
                {{ showHidden ? 'Try adjusting your search or filters.' : 'There are no visible templates.' }}
             </p>
         </div>
      </div>
    </div>
    <div v-if="error" class="px-4 py-2 text-sm text-red-600 dark:text-red-400 bg-red-50 dark:bg-red-900/20 border-t border-red-200 dark:border-red-800">
        {{ error }}
    </div>
  </div>
</template>

<script>
import { db } from '../firebase';
import { collection, query, orderBy, getDocs, doc, updateDoc } from 'firebase/firestore';

export default {
  name: 'Templates',
  data() {
    return {
      templates: [],
      loading: true,
      error: null,
      showHidden: false,
      sortKey: 'updatedAt', // Default sort by date
      sortDesc: true        // Default sort descending (newest first)
    }
  },
  computed: {
    filteredTemplates() {
      // 1. Filter by hidden status
      let result = this.templates.filter(t => this.showHidden || !t.hidden);

      // 2. Sort
      return result.sort((a, b) => {
        let valA = a[this.sortKey];
        let valB = b[this.sortKey];

        // Handle fallback for timestamps (updatedAt might be missing, use createdAt)
        if (this.sortKey === 'updatedAt') {
            valA = valA || a.createdAt;
            valB = valB || b.createdAt;
        }

        // Extract seconds if it's a Firestore Timestamp
        if (valA && typeof valA === 'object' && valA.seconds) valA = valA.seconds;
        if (valB && typeof valB === 'object' && valB.seconds) valB = valB.seconds;

        // String comparison case insensitivity
        if (typeof valA === 'string') valA = valA.toLowerCase();
        if (typeof valB === 'string') valB = valB.toLowerCase();

        if (valA < valB) return this.sortDesc ? 1 : -1;
        if (valA > valB) return this.sortDesc ? -1 : 1;
        return 0;
      });
    }
  },
  async mounted() {
    await this.fetchTemplates();
  },
  methods: {
    async fetchTemplates() {
      try {
        const q = query(collection(db, "templates"), orderBy("createdAt", "desc"));
        const querySnapshot = await getDocs(q);
        this.templates = querySnapshot.docs.map(doc => ({
          id: doc.id,
          ...doc.data()
        }));
      } catch (e) {
        console.error("Error fetching templates:", e);
        this.error = "Failed to load templates.";
      } finally {
        this.loading = false;
      }
    },
    formatDate(timestamp) {
      if (!timestamp) return 'N/A';
      // Handle Firestore Timestamp or standard JS Date
      const date = timestamp.seconds ? new Date(timestamp.seconds * 1000) : new Date(timestamp);
      return date.toLocaleDateString() + ' ' + date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    },
    selectTemplate(template) {
        this.$router.push({
            name: 'Generate',
            params: { templateData: template }
        });
    },
    async toggleHidden(template) {
        try {
            const newHiddenState = !template.hidden;
            // Update in Firestore
            const templateRef = doc(db, "templates", template.id);
            await updateDoc(templateRef, {
                hidden: newHiddenState
            });
            // Update locally using $set for Vue 2 reactivity
            this.$set(template, 'hidden', newHiddenState);
        } catch (e) {
            console.error("Error updating template hidden status:", e);
            this.error = "Failed to update template status. " + e.message;
        }
    },
    setSort(key) {
        if (this.sortKey === key) {
            this.sortDesc = !this.sortDesc;
        } else {
            this.sortKey = key;
            // Default sort order: Name/Author -> Asc, Date -> Desc
            if (key === 'updatedAt') {
                this.sortDesc = true;
            } else {
                this.sortDesc = false;
            }
        }
    }
  }
}
</script>
