<template>
  <div class="bg-white dark:bg-gray-800 shadow sm:rounded-lg">
    <div class="px-4 py-5 sm:p-6" v-if="interaction">
      <div class="flex items-center justify-between mb-6">
        <h3 class="text-lg leading-6 font-medium text-gray-900 dark:text-gray-100">
          Interaction Details
        </h3>
        <div class="flex space-x-4">
             <button @click="loadInGenerate" class="text-sm text-green-600 dark:text-green-400 hover:text-green-900 dark:hover:text-green-300">
                Open in Generate
             </button>
             <button @click="copyInteraction" class="text-sm text-indigo-600 dark:text-indigo-400 hover:text-indigo-900 dark:hover:text-indigo-300">
                Copy Details
             </button>
             <router-link to="/history" class="text-sm text-indigo-600 dark:text-indigo-400 hover:text-indigo-900 dark:hover:text-indigo-300">
                &larr; Back to History
             </router-link>
        </div>
      </div>

      <div class="border-t border-gray-200 dark:border-gray-700">
        <dl>
          <div class="bg-gray-50 dark:bg-gray-700 px-4 py-5 sm:grid sm:grid-cols-3 sm:gap-4 sm:px-6">
            <dt class="text-sm font-medium text-gray-500 dark:text-gray-300">ID</dt>
            <dd class="mt-1 text-sm text-gray-900 dark:text-gray-100 sm:mt-0 sm:col-span-2">{{ interaction.id }}</dd>
          </div>
          <div class="bg-white dark:bg-gray-800 px-4 py-5 sm:grid sm:grid-cols-3 sm:gap-4 sm:px-6">
            <dt class="text-sm font-medium text-gray-500 dark:text-gray-300">Timestamp</dt>
            <dd class="mt-1 text-sm text-gray-900 dark:text-gray-100 sm:mt-0 sm:col-span-2">{{ formatDate(interaction.timestamp) }}</dd>
          </div>
          <div class="bg-gray-50 dark:bg-gray-700 px-4 py-5 sm:grid sm:grid-cols-3 sm:gap-4 sm:px-6">
            <dt class="text-sm font-medium text-gray-500 dark:text-gray-300">User</dt>
            <dd class="mt-1 text-sm text-gray-900 dark:text-gray-100 sm:mt-0 sm:col-span-2">{{ interaction.user }}</dd>
          </div>
          <div class="bg-white dark:bg-gray-800 px-4 py-5 sm:grid sm:grid-cols-3 sm:gap-4 sm:px-6">
            <dt class="text-sm font-medium text-gray-500 dark:text-gray-300">Model</dt>
            <dd class="mt-1 text-sm text-gray-900 dark:text-gray-100 sm:mt-0 sm:col-span-2">{{ interaction.model }}</dd>
          </div>
           <div class="bg-gray-50 dark:bg-gray-700 px-4 py-5 sm:grid sm:grid-cols-3 sm:gap-4 sm:px-6">
            <dt class="text-sm font-medium text-gray-500 dark:text-gray-300">Cost</dt>
            <dd class="mt-1 text-sm text-gray-900 dark:text-gray-100 sm:mt-0 sm:col-span-2">${{ interaction.cost }}</dd>
          </div>
          <div class="bg-white dark:bg-gray-800 px-4 py-5 sm:grid sm:grid-cols-3 sm:gap-4 sm:px-6">
            <dt class="text-sm font-medium text-gray-500 dark:text-gray-300">Response</dt>
            <dd class="mt-1 text-sm text-gray-900 dark:text-gray-100 sm:mt-0 sm:col-span-2 whitespace-pre-wrap">{{ interaction.response }}</dd>
          </div>
          <div class="bg-gray-50 dark:bg-gray-700 px-4 py-5 sm:grid sm:grid-cols-3 sm:gap-4 sm:px-6">
            <dt class="text-sm font-medium text-gray-500 dark:text-gray-300">Payload</dt>
            <dd class="mt-1 text-sm text-gray-900 dark:text-gray-100 sm:mt-0 sm:col-span-2">
                 <div class="text-xs bg-gray-100 dark:bg-gray-900 dark:text-gray-300 p-2 rounded overflow-x-auto whitespace-pre-wrap" v-html="formatPayload(interaction.payload)"></div>
            </dd>
          </div>
        </dl>
      </div>
    </div>
    <div v-else-if="loading" class="p-6 text-gray-500">
        Loading...
    </div>
    <div v-else class="p-6 text-red-500">
        Interaction not found.
    </div>
  </div>
</template>

<script>
import { db } from '../firebase';
import { doc, getDoc } from 'firebase/firestore';
import { formatInteractionForClipboard, copyToClipboard } from '../utils/clipboard';
import { formatDate } from '../utils/date';
import { showToast } from '../utils/toast';

export default {
  name: 'HistoryDetail',
  data() {
    return {
      interaction: null,
      loading: true
    }
  },
  async mounted() {
    const id = this.$route.params.id;
    if (id) {
        await this.fetchInteraction(id);
    }
  },
  methods: {
    async fetchInteraction(id) {
        try {
            const docRef = doc(db, "interaction_logs", id);
            const docSnap = await getDoc(docRef);

            if (docSnap.exists()) {
                this.interaction = { id: docSnap.id, ...docSnap.data() };
            } else {
                console.error("No such document!");
            }
        } catch (e) {
            console.error("Error fetching doc:", e);
        } finally {
            this.loading = false;
        }
    },
    formatDate,
    formatPayload(payload) {
        if (!payload) return '';
        const json = JSON.stringify(payload, null, 2);
        // Regex to find URLs and replace with <a> tags
        return json.replace(/("url":\s*")([^"]+)(")/g, (match, p1, p2, p3) => {
            if (p2.startsWith('http')) {
                 const cleanUrl = p2.replace('&export=download', '');
                 return `${p1}<a href="${cleanUrl}" target="_blank" class="text-blue-500 dark:text-blue-400 hover:underline">${cleanUrl}</a>${p3}`;
            }
            return match;
        });

    },
    async copyInteraction() {
        if (!this.interaction) return;
        const text = formatInteractionForClipboard(this.interaction);
        if (await copyToClipboard(text)) {
             showToast('Copied to clipboard!');
        } else {
             showToast('Failed to copy', 'error');
        }
    },
    loadInGenerate() {
        if (!this.interaction) return;

        let conversationHistory = [];

        if (this.interaction.conversation_history) {
            // 1a. Load from rich history (includes costs, metadata)
            conversationHistory = JSON.parse(JSON.stringify(this.interaction.conversation_history));

            // Ensure the last turn references this interaction Log ID
            if (conversationHistory.length > 0) {
                const lastTurn = conversationHistory[conversationHistory.length - 1];
                if (lastTurn.type === 'assistant') {
                    lastTurn.docId = this.interaction.id;
                    // Ensure cost matches the total stored if needed, but Generate saves cumulative in the log
                    // cost field AND in the turn.cost.
                }
            }
        } else {
            // 1b. Legacy: Reconstruct history from 'messages' payload
            const payload = this.interaction.payload || {};
            const messages = payload.messages || [];

            // 1. Reconstruct history from previous turns (User + Assistant) stored in payload
            messages.forEach(msg => {
                if (msg.role === 'user') {
                    // Reconstruct User Turn
                    const turn = {
                        type: 'user',
                        content: msg.content, // Raw content for API context
                        prompts: [] // Visual representation
                    };

                    // Derive prompts from content for display
                    turn.prompts = [];
                    let currentPrompt = { text: '', attachments: [] };

                    if (Array.isArray(msg.content)) {
                        msg.content.forEach(part => {
                            if (part.type === 'text') {
                                // If we already have content (text or attachments), start a new prompt
                                // because text always comes at the start of a prompt block in our payload structure
                                if (currentPrompt.text || currentPrompt.attachments.length > 0) {
                                    turn.prompts.push(currentPrompt);
                                    currentPrompt = { text: '', attachments: [] };
                                }
                                currentPrompt.text = part.text;
                            } else {
                                // Handle Attachments
                                let att = null;
                                if (part.type === 'image_url') {
                                    att = {
                                        type: 'image/url',
                                        content: part.image_url.url,
                                        name: 'Image',
                                        previewUrl: part.image_url.url
                                    };
                                } else if (part.type === 'file_url') {
                                    const url = part.file_url.url;
                                    const title = part.file_url.title || 'Google Doc';
                                    let docId = null;
                                    const match = url.match(/\/d\/([a-zA-Z0-9-_]+)/);
                                    if (match) docId = match[1];

                                    att = {
                                        type: 'application/vnd.google-apps.document',
                                        name: title,
                                        docId: docId,
                                        webViewLink: url
                                    };
                                }

                                if (att) {
                                    currentPrompt.attachments.push(att);
                                }
                            }
                        });
                    } else if (typeof msg.content === 'string') {
                        currentPrompt.text = msg.content;
                    }

                    // Push remaining
                    if (currentPrompt.text || currentPrompt.attachments.length > 0) {
                        turn.prompts.push(currentPrompt);
                    }

                    conversationHistory.push(turn);

                } else if (msg.role === 'assistant') {
                    // Reconstruct Assistant Turn
                    conversationHistory.push({
                        type: 'assistant',
                        text: typeof msg.content === 'string' ? msg.content : JSON.stringify(msg.content),
                        model: payload.model || this.interaction.model
                    });
                }
            });

            // 2. Add the response from THIS interaction as the final Assistant turn
            // Only if not already present in payload (dedup check)
            const lastMsg = messages[messages.length - 1];
            const alreadyHasResponse = lastMsg && lastMsg.role === 'assistant';

            // Additional safety: if the payload seems to be "Log-style" (includes response), don't add.
            // If it's "Request-style" (excludes response), add it.
            // Our new logger writes "Log-style". Old logs might be "Request-style".
            if (!alreadyHasResponse && this.interaction.response) {
                conversationHistory.push({
                    type: 'assistant',
                    text: this.interaction.response,
                    model: this.interaction.model || payload.model,
                    cost: this.interaction.cost,
                    docId: this.interaction.id
                });
            } else if (alreadyHasResponse) {
                // Ensure the last assistant turn in history gets the metadata
                const lastTurn = conversationHistory[conversationHistory.length - 1];
                if (lastTurn && lastTurn.type === 'assistant') {
                    lastTurn.cost = this.interaction.cost;
                    lastTurn.docId = this.interaction.id;
                }
            }
        } // End else legacy logic

        // Calculate Cost to date fallback?
        // If we loaded from rich history, costs are internal.
        // If we loaded from legacy, costs are missing from intermediate turns.
        // But for the last turn, we have 'cost'.
        // To be consistent with the user's request "show the cost for all generations",
        // we can't easily retro-fill old logs. But we have setup new logs to work.

        const templateData = {
            model: this.interaction.model || (this.interaction.payload ? this.interaction.payload.model : null), // Ensure payload.model is accessed safely
            conversationHistory: conversationHistory,
            prompts: [] // Start with empty input for next turn
        };

        this.$router.push({ name: 'Generate', params: { templateData } });
    }
  }
}
</script>
